 Begin StcResourceProfile 	# Resource coverage
    Ident = "AllSky-CXO" 	# Permanent Object identification string
 IsA Object 	# AST Object
#   Title = "4-d compound coordinate system" 	# Title of coordinate system
#   Naxes = 4 	# Number of coordinate axes
#   Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
#   Epoch = 1999.556924480934 	# Julian epoch of observation
#   Lbl1 = "Right ascension" 	# Label for axis 1
#   Lbl2 = "Declination" 	# Label for axis 2
#   Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#   Lbl4 = "Energy" 	# Label for axis 4
#   System = "Compound" 	# Coordinate system type
#   Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#   Uni2 = "ddd:mm:ss" 	# Units for axis 2
#   Uni3 = "d" 	# Units for axis 3 (day)
#   Uni4 = "keV" 	# Units for axis 4
#   Dir1 = 0 	# Plot axis 1 in reverse direction
 IsA Frame 	# Coordinate system description
    Fill = 0.02 	# Region fill factor
    Adapt = 1 	# Region adapts to coord sys changes
    FrmSet = 	# Original & current coordinate systems
       Begin FrameSet 	# Set of inter-related coordinate systems
#         Title = "4-d compound coordinate system" 	# Title of coordinate system
#         Naxes = 4 	# Number of coordinate axes
#         Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
#         Epoch = 1999.556924480934 	# Julian epoch of observation
#         Lbl1 = "Right ascension" 	# Label for axis 1
#         Lbl2 = "Declination" 	# Label for axis 2
#         Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#         Lbl4 = "Energy" 	# Label for axis 4
#         System = "Compound" 	# Coordinate system type
#         Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#         Uni2 = "ddd:mm:ss" 	# Units for axis 2
#         Uni3 = "d" 	# Units for axis 3 (day)
#         Uni4 = "keV" 	# Units for axis 4
#         Dir1 = 0 	# Plot axis 1 in reverse direction
       IsA Frame 	# Coordinate system description
          Nframe = 2 	# Number of Frames in FrameSet
#         Base = 1 	# Index of base Frame
          Currnt = 2 	# Index of current Frame
          Lnk2 = 1 	# Node 2 is derived from node 1
          Frm1 = 	# Frame number 1
             Begin CmpFrame 	# Compound coordinate system description
                Ident = "ICRS-TT-CXO" 	# Permanent Object identification string
             IsA Object 	# AST Object
#               Title = "4-d compound coordinate system" 	# Title of coordinate system
#               Naxes = 4 	# Number of coordinate axes
#               Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
                Epoch = 1999.556924480934 	# Julian epoch of observation
#               Lbl1 = "Right ascension" 	# Label for axis 1
#               Lbl2 = "Declination" 	# Label for axis 2
#               Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#               Lbl4 = "Energy" 	# Label for axis 4
#               Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#               Uni2 = "ddd:mm:ss" 	# Units for axis 2
#               Uni3 = "d" 	# Units for axis 3 (day)
#               Uni4 = "keV" 	# Units for axis 4
#               Dir1 = 0 	# Plot axis 1 in reverse direction
             IsA Frame 	# Coordinate system description
                FrameA = 	# First component Frame
                   Begin CmpFrame 	# Compound coordinate system description
                      Epoch = 1999.556924480934 	# Julian epoch of observation
                   IsA Frame 	# Coordinate system description
                      FrameA = 	# First component Frame
                         Begin SkyFrame 	# Description of celestial coordinate system
                            Title = "Space" 	# Title of coordinate system
                            Naxes = 2 	# Number of coordinate axes
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                            System = "ICRS" 	# Coordinate system type
                            Ax1 = 	# Axis number 1
                               Begin SkyAxis 	# Celestial coordinate axis
                               End SkyAxis
                            Ax2 = 	# Axis number 2
                               Begin SkyAxis 	# Celestial coordinate axis
                               End SkyAxis
                         IsA Frame 	# Coordinate system description
                         End SkyFrame
                      FrameB = 	# Second component Frame
                         Begin TimeFrame 	# Description of time coordinate system
                            Title = "Time" 	# Title of coordinate system
                            Naxes = 1 	# Number of coordinate axes
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                            System = "MJD" 	# Coordinate system type
                            Ax1 = 	# Axis number 1
                               Begin Axis 	# Coordinate axis
                                  Unit = "d" 	# Axis units (day)
                               End Axis
                         IsA Frame 	# Coordinate system description
                            TmScl = "TT" 	# Time scale
                            TmOrg = 51382.666666666664 	# Time offset
                         End TimeFrame
                   End CmpFrame
                FrameB = 	# Second component Frame
                   Begin SpecFrame 	# Description of spectral coordinate system
                      Naxes = 1 	# Number of coordinate axes
                      Epoch = 1999.556924480934 	# Julian epoch of observation
                      System = "ENER" 	# Coordinate system type
                      Ax1 = 	# Axis number 1
                         Begin Axis 	# Coordinate axis
                            Unit = "keV" 	# Axis units
                         End Axis
                   IsA Frame 	# Coordinate system description
                      SoR = "Topocentric" 	# Standard of rest
                      UEner = "keV" 	# Preferred units for energy
                   End SpecFrame
             End CmpFrame
          Frm2 = 	# Frame number 2
             Begin CmpFrame 	# Compound coordinate system description
                Ident = "ICRS-TT-CXO" 	# Permanent Object identification string
             IsA Object 	# AST Object
#               Title = "4-d compound coordinate system" 	# Title of coordinate system
#               Naxes = 4 	# Number of coordinate axes
#               Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
                Epoch = 1999.556924480934 	# Julian epoch of observation
#               Lbl1 = "Right ascension" 	# Label for axis 1
#               Lbl2 = "Declination" 	# Label for axis 2
#               Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#               Lbl4 = "Energy" 	# Label for axis 4
#               Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#               Uni2 = "ddd:mm:ss" 	# Units for axis 2
#               Uni3 = "d" 	# Units for axis 3 (day)
#               Uni4 = "keV" 	# Units for axis 4
#               Dir1 = 0 	# Plot axis 1 in reverse direction
             IsA Frame 	# Coordinate system description
                FrameA = 	# First component Frame
                   Begin CmpFrame 	# Compound coordinate system description
                      Epoch = 1999.556924480934 	# Julian epoch of observation
                   IsA Frame 	# Coordinate system description
                      FrameA = 	# First component Frame
                         Begin SkyFrame 	# Description of celestial coordinate system
                            Title = "Space" 	# Title of coordinate system
                            Naxes = 2 	# Number of coordinate axes
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                            System = "ICRS" 	# Coordinate system type
                            Ax1 = 	# Axis number 1
                               Begin SkyAxis 	# Celestial coordinate axis
                               End SkyAxis
                            Ax2 = 	# Axis number 2
                               Begin SkyAxis 	# Celestial coordinate axis
                               End SkyAxis
                         IsA Frame 	# Coordinate system description
                         End SkyFrame
                      FrameB = 	# Second component Frame
                         Begin TimeFrame 	# Description of time coordinate system
                            Title = "Time" 	# Title of coordinate system
                            Naxes = 1 	# Number of coordinate axes
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                            System = "MJD" 	# Coordinate system type
                            Ax1 = 	# Axis number 1
                               Begin Axis 	# Coordinate axis
                                  Unit = "d" 	# Axis units (day)
                               End Axis
                         IsA Frame 	# Coordinate system description
                            TmScl = "TT" 	# Time scale
                            TmOrg = 51382.666666666664 	# Time offset
                         End TimeFrame
                   End CmpFrame
                FrameB = 	# Second component Frame
                   Begin SpecFrame 	# Description of spectral coordinate system
                      Naxes = 1 	# Number of coordinate axes
                      Epoch = 1999.556924480934 	# Julian epoch of observation
                      System = "ENER" 	# Coordinate system type
                      Ax1 = 	# Axis number 1
                         Begin Axis 	# Coordinate axis
                            Unit = "keV" 	# Axis units
                         End Axis
                   IsA Frame 	# Coordinate system description
                      SoR = "Topocentric" 	# Standard of rest
                      UEner = "keV" 	# Preferred units for energy
                   End SpecFrame
             End CmpFrame
          Map2 = 	# Mapping between nodes 1 and 2
             Begin CmpMap 	# Compound Mapping
                Nin = 4 	# Number of input coordinates
                IsSimp = 1 	# Mapping has been simplified
             IsA Mapping 	# Mapping between coordinate systems
                Series = 0 	# Component Mappings applied in parallel
                MapA = 	# First component Mapping
                   Begin CmpMap 	# Compound Mapping
                      Nin = 3 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Series = 0 	# Component Mappings applied in parallel
                      MapA = 	# First component Mapping
                         Begin UnitMap 	# Unit (null) Mapping
                            Nin = 2 	# Number of input coordinates
                            IsSimp = 1 	# Mapping has been simplified
                         IsA Mapping 	# Mapping between coordinate systems
                         End UnitMap
                      MapB = 	# Second component Mapping
                         Begin CmpMap 	# Compound Mapping
                            Nin = 1 	# Number of input coordinates
                            IsSimp = 1 	# Mapping has been simplified
                         IsA Mapping 	# Mapping between coordinate systems
                            MapA = 	# First component Mapping
                               Begin CmpMap 	# Compound Mapping
                                  Nin = 1 	# Number of input coordinates
                                  IsSimp = 1 	# Mapping has been simplified
                               IsA Mapping 	# Mapping between coordinate systems
                                  MapA = 	# First component Mapping
                                     Begin TimeMap 	# Conversion between time coordinate systems
                                        Nin = 1 	# Number of input coordinates
                                     IsA Mapping 	# Mapping between coordinate systems
                                        Ntime = 2 	# Number of conversion steps
                                        Time1 = "TTTOTAI" 	# Convert TT to TAI
                                        Time1a = 51382.666666666664 	# MJD offset
                                        Time2 = "MJDTOMJD" 	# Convert MJD between offsets
                                        Time2a = 51382.666666666664 	# Input MJD offset
                                        Time2b = 51382.665921666667 	# Output MJD offset
                                        Time2c = 0.00074499999755062163 	# Combined offset
                                     End TimeMap
                                  MapB = 	# Second component Mapping
                                     Begin ShiftMap 	# Shift each coordinate axis
                                        Nin = 1 	# Number of input coordinates
                                     IsA Mapping 	# Mapping between coordinate systems
                                        Sft1 = -0.00037249999877531081 	# Shift for axis 1
                                     End ShiftMap
                               End CmpMap
                            MapB = 	# Second component Mapping
                               Begin CmpMap 	# Compound Mapping
                                  Nin = 1 	# Number of input coordinates
                                  IsSimp = 1 	# Mapping has been simplified
                               IsA Mapping 	# Mapping between coordinate systems
                                  MapA = 	# First component Mapping
                                     Begin TimeMap 	# Conversion between time coordinate systems
                                        Nin = 1 	# Number of input coordinates
                                     IsA Mapping 	# Mapping between coordinate systems
                                        Ntime = 2 	# Number of conversion steps
                                        Time1 = "TAITOTT" 	# Convert TAI to TT
                                        Time1a = 51382.666294166665 	# MJD offset
                                        Time2 = "MJDTOMJD" 	# Convert MJD between offsets
                                        Time2a = 51382.666294166665 	# Input MJD offset
                                        Time2b = 51382.667039166663 	# Output MJD offset
                                        Time2c = -0.00074499999755062163 	# Combined offset
                                     End TimeMap
                                  MapB = 	# Second component Mapping
                                     Begin ShiftMap 	# Shift each coordinate axis
                                        Nin = 1 	# Number of input coordinates
                                     IsA Mapping 	# Mapping between coordinate systems
                                        Sft1 = 0.00037249999877531081 	# Shift for axis 1
                                     End ShiftMap
                               End CmpMap
                         End CmpMap
                   End CmpMap
                MapB = 	# Second component Mapping
                   Begin UnitMap 	# Unit (null) Mapping
                      Nin = 1 	# Number of input coordinates
                      IsSimp = 1 	# Mapping has been simplified
                   IsA Mapping 	# Mapping between coordinate systems
                   End UnitMap
             End CmpMap
       End FrameSet
    RegAxes = 4 	# Number of axes spanned by the Region
 IsA Region 	# An area within a coordinate system
    Region = 	# STC Region
       Begin Interval 	# Axis intervals
          Ident = "AllSky-CXO" 	# Permanent Object identification string
       IsA Object 	# AST Object
#         Title = "4-d compound coordinate system" 	# Title of coordinate system
#         Naxes = 4 	# Number of coordinate axes
#         Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
#         Epoch = 1999.556924480934 	# Julian epoch of observation
#         Lbl1 = "Right ascension" 	# Label for axis 1
#         Lbl2 = "Declination" 	# Label for axis 2
#         Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#         Lbl4 = "Energy" 	# Label for axis 4
#         System = "Compound" 	# Coordinate system type
#         Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#         Uni2 = "ddd:mm:ss" 	# Units for axis 2
#         Uni3 = "d" 	# Units for axis 3 (day)
#         Uni4 = "keV" 	# Units for axis 4
#         Dir1 = 0 	# Plot axis 1 in reverse direction
       IsA Frame 	# Coordinate system description
          Fill = 0.02 	# Region fill factor
          Adapt = 1 	# Region adapts to coord sys changes
          Frm = 	# Coordinate system
             Begin CmpFrame 	# Compound coordinate system description
                Ident = "ICRS-TT-CXO" 	# Permanent Object identification string
             IsA Object 	# AST Object
#               Title = "4-d compound coordinate system" 	# Title of coordinate system
#               Naxes = 4 	# Number of coordinate axes
#               Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
                Epoch = 1999.556924480934 	# Julian epoch of observation
#               Lbl1 = "Right ascension" 	# Label for axis 1
#               Lbl2 = "Declination" 	# Label for axis 2
#               Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#               Lbl4 = "Energy" 	# Label for axis 4
#               Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#               Uni2 = "ddd:mm:ss" 	# Units for axis 2
#               Uni3 = "d" 	# Units for axis 3 (day)
#               Uni4 = "keV" 	# Units for axis 4
#               Dir1 = 0 	# Plot axis 1 in reverse direction
             IsA Frame 	# Coordinate system description
                FrameA = 	# First component Frame
                   Begin CmpFrame 	# Compound coordinate system description
                      Epoch = 1999.556924480934 	# Julian epoch of observation
                   IsA Frame 	# Coordinate system description
                      FrameA = 	# First component Frame
                         Begin SkyFrame 	# Description of celestial coordinate system
                            Title = "Space" 	# Title of coordinate system
                            Naxes = 2 	# Number of coordinate axes
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                            System = "ICRS" 	# Coordinate system type
                            Ax1 = 	# Axis number 1
                               Begin SkyAxis 	# Celestial coordinate axis
                               End SkyAxis
                            Ax2 = 	# Axis number 2
                               Begin SkyAxis 	# Celestial coordinate axis
                               End SkyAxis
                         IsA Frame 	# Coordinate system description
                         End SkyFrame
                      FrameB = 	# Second component Frame
                         Begin TimeFrame 	# Description of time coordinate system
                            Title = "Time" 	# Title of coordinate system
                            Naxes = 1 	# Number of coordinate axes
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                            System = "MJD" 	# Coordinate system type
                            Ax1 = 	# Axis number 1
                               Begin Axis 	# Coordinate axis
                                  Unit = "d" 	# Axis units (day)
                               End Axis
                         IsA Frame 	# Coordinate system description
                            TmScl = "TT" 	# Time scale
                            TmOrg = 51382.666666666664 	# Time offset
                         End TimeFrame
                   End CmpFrame
                FrameB = 	# Second component Frame
                   Begin SpecFrame 	# Description of spectral coordinate system
                      Naxes = 1 	# Number of coordinate axes
                      Epoch = 1999.556924480934 	# Julian epoch of observation
                      System = "ENER" 	# Coordinate system type
                      Ax1 = 	# Axis number 1
                         Begin Axis 	# Coordinate axis
                            Unit = "keV" 	# Axis units
                         End Axis
                   IsA Frame 	# Coordinate system description
                      SoR = "Topocentric" 	# Standard of rest
                      UEner = "keV" 	# Preferred units for energy
                   End SpecFrame
             End CmpFrame
          Points = 	# Points defining the shape
             Begin PointSet 	# Container for a set of points
                Npoint = 2 	# Number of points
                Ncoord = 4 	# Number of coordinates per point
                X3 = 0 	# Coordinate values...
                X4 = 0.12
                X8 = 10
             End PointSet
          Unc = 	# Region defining positional uncertainties.
             Begin Box 	# Axis intervals
#               Title = "4-d compound coordinate system" 	# Title of coordinate system
#               Naxes = 4 	# Number of coordinate axes
#               Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
#               Epoch = 1999.556924480934 	# Julian epoch of observation
#               Lbl1 = "Right ascension" 	# Label for axis 1
#               Lbl2 = "Declination" 	# Label for axis 2
#               Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#               Lbl4 = "Energy" 	# Label for axis 4
#               System = "Compound" 	# Coordinate system type
#               Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#               Uni2 = "ddd:mm:ss" 	# Units for axis 2
#               Uni3 = "d" 	# Units for axis 3 (day)
#               Uni4 = "keV" 	# Units for axis 4
#               Dir1 = 0 	# Plot axis 1 in reverse direction
             IsA Frame 	# Coordinate system description
                Adapt = 1 	# Region adapts to coord sys changes
                Frm = 	# Coordinate system
                   Begin CmpFrame 	# Compound coordinate system description
#                     Title = "4-d compound coordinate system" 	# Title of coordinate system
#                     Naxes = 4 	# Number of coordinate axes
#                     Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
                      Epoch = 1999.556924480934 	# Julian epoch of observation
#                     Lbl1 = "Right ascension" 	# Label for axis 1
#                     Lbl2 = "Declination" 	# Label for axis 2
#                     Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#                     Lbl4 = "Energy" 	# Label for axis 4
#                     Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#                     Uni2 = "ddd:mm:ss" 	# Units for axis 2
#                     Uni3 = "d" 	# Units for axis 3 (day)
#                     Uni4 = "keV" 	# Units for axis 4
#                     Dir1 = 0 	# Plot axis 1 in reverse direction
                   IsA Frame 	# Coordinate system description
                      FrameA = 	# First component Frame
                         Begin CmpFrame 	# Compound coordinate system description
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                         IsA Frame 	# Coordinate system description
                            FrameA = 	# First component Frame
                               Begin SkyFrame 	# Description of celestial coordinate system
                                  Title = "Space" 	# Title of coordinate system
                                  Naxes = 2 	# Number of coordinate axes
                                  Epoch = 1999.556924480934 	# Julian epoch of observation
                                  System = "ICRS" 	# Coordinate system type
                                  Ax1 = 	# Axis number 1
                                     Begin SkyAxis 	# Celestial coordinate axis
                                     End SkyAxis
                                  Ax2 = 	# Axis number 2
                                     Begin SkyAxis 	# Celestial coordinate axis
                                     End SkyAxis
                               IsA Frame 	# Coordinate system description
                               End SkyFrame
                            FrameB = 	# Second component Frame
                               Begin TimeFrame 	# Description of time coordinate system
                                  Title = "Time" 	# Title of coordinate system
                                  Naxes = 1 	# Number of coordinate axes
                                  Epoch = 1999.556924480934 	# Julian epoch of observation
                                  System = "MJD" 	# Coordinate system type
                                  Ax1 = 	# Axis number 1
                                     Begin Axis 	# Coordinate axis
                                        Unit = "d" 	# Axis units (day)
                                     End Axis
                               IsA Frame 	# Coordinate system description
                                  TmScl = "TT" 	# Time scale
                                  TmOrg = 51382.666666666664 	# Time offset
                               End TimeFrame
                         End CmpFrame
                      FrameB = 	# Second component Frame
                         Begin SpecFrame 	# Description of spectral coordinate system
                            Naxes = 1 	# Number of coordinate axes
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                            System = "ENER" 	# Coordinate system type
                            Ax1 = 	# Axis number 1
                               Begin Axis 	# Coordinate axis
                                  Unit = "keV" 	# Axis units
                               End Axis
                         IsA Frame 	# Coordinate system description
                            SoR = "Topocentric" 	# Standard of rest
                            UEner = "keV" 	# Preferred units for energy
                         End SpecFrame
                   End CmpFrame
                Points = 	# Points defining the shape
                   Begin PointSet 	# Container for a set of points
                      Npoint = 2 	# Number of points
                      Ncoord = 4 	# Number of coordinates per point
                      X1 = 0 	# Coordinate values...
                      X2 = 0
                      X3 = 0
                      X4 = 0.12
                      X5 = 2.4240684055495722e-06
                      X6 = 2.4240684055430873e-06
                      X7 = 5.7870370370370369e-10
                      X8 = 0.16999999999999998
                   End PointSet
             IsA Region 	# An area within a coordinate system
             End Box
       IsA Region 	# An area within a coordinate system
       End Interval
    Ncoord = 1 	# Number of AstroCoords elements
    Coord1 = 	# AstroCoords number 1
       Begin KeyMap 	# Map of key/value pairs
          MapSz = 16 	# Size of hash table
          MemCnt = 8 	# Total member count
          Key1 = "Size" 	# Item name
          Typ1 = 4 	# Item data type (AST Object)
          Val1 = 	# Item value
             Begin Box 	# Axis intervals
#               Title = "4-d compound coordinate system" 	# Title of coordinate system
#               Naxes = 4 	# Number of coordinate axes
#               Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
#               Epoch = 1999.556924480934 	# Julian epoch of observation
#               Lbl1 = "Right ascension" 	# Label for axis 1
#               Lbl2 = "Declination" 	# Label for axis 2
#               Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#               Lbl4 = "Energy" 	# Label for axis 4
#               System = "Compound" 	# Coordinate system type
#               Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#               Uni2 = "ddd:mm:ss" 	# Units for axis 2
#               Uni3 = "d" 	# Units for axis 3 (day)
#               Uni4 = "keV" 	# Units for axis 4
#               Dir1 = 0 	# Plot axis 1 in reverse direction
             IsA Frame 	# Coordinate system description
                Adapt = 1 	# Region adapts to coord sys changes
                Frm = 	# Coordinate system
                   Begin CmpFrame 	# Compound coordinate system description
                      Ident = "ICRS-TT-CXO" 	# Permanent Object identification string
                   IsA Object 	# AST Object
#                     Title = "4-d compound coordinate system" 	# Title of coordinate system
#                     Naxes = 4 	# Number of coordinate axes
#                     Domain = "SKY-TIME-SPECTRUM" 	# Coordinate system domain
                      Epoch = 1999.556924480934 	# Julian epoch of observation
#                     Lbl1 = "Right ascension" 	# Label for axis 1
#                     Lbl2 = "Declination" 	# Label for axis 2
#                     Lbl3 = "Modified Julian Date offset from 1999-07-23 16:00:00" 	# Label for axis 3
#                     Lbl4 = "Energy" 	# Label for axis 4
#                     Uni1 = "hh:mm:ss.s" 	# Units for axis 1
#                     Uni2 = "ddd:mm:ss" 	# Units for axis 2
#                     Uni3 = "d" 	# Units for axis 3 (day)
#                     Uni4 = "keV" 	# Units for axis 4
#                     Dir1 = 0 	# Plot axis 1 in reverse direction
                   IsA Frame 	# Coordinate system description
                      FrameA = 	# First component Frame
                         Begin CmpFrame 	# Compound coordinate system description
                            Epoch = 1999.556924480934 	# Julian epoch of observation
                         IsA Frame 	# Coordinate system description
                            FrameA = 	# First component Frame
                               Begin SkyFrame 	# Description of celestial coordinate system
                                  Title = "Space" 	# Title of coordinate system
                                  Naxes = 2 	# Number of coordinate axes
                                  Epoch = 1999.556924480934 	# Julian epoch of observation
                                  System = "ICRS" 	# Coordinate system type
                                  Ax1 = 	# Axis number 1
                                     Begin SkyAxis 	# Celestial coordinate axis
                                     End SkyAxis
                                  Ax2 = 	# Axis number 2
                                     Begin SkyAxis 	# Celestial coordinate axis
                                     End SkyAxis
                               IsA Frame 	# Coordinate system description
                               End SkyFrame
                            FrameB = 	# Second component Frame
                               Begin TimeFrame 	# Description of time coordinate system
                                  Title = "Time" 	# Title of coordinate system
                                  Naxes = 1 	# Number of coordinate axes
                                  Epoch = 1999.556924480934 	# Julian epoch of observation
                                  System = "MJD" 	# Coordinate system type
                                  Ax1 = 	# Axis number 1
                                     Begin Axis 	# Coordinate axis
                                        Unit = "d" 	# Axis units (day)
                                     End Axis
                               IsA Frame 	# Coordinate system description
